import { d3_map, d3_select, d3_event } from '../core/d3-constants';

/**
 *
 * @type {boolean}
 * @private
 */

let __META_KEY_INITIALIZED = false;
let __META_EVENT = null;
let __HOOKS = d3_map();
let __HOOK_ID = 0;

/**
 *
 */
class KEYBOARD_EVENT_HANDLER {
    /**
     *
     * @private
     */
    static __INIT_EVENT() {
        if (!__META_KEY_INITIALIZED) {
            let WIN = d3_select(window);
            WIN.on(`keydown.__META_KEY_ZC`, () => {
                __META_EVENT = d3_event();

                __HOOKS.each((hook, key) => {
                    let hookKey = key.split('.').shift();
                    if (KEYBOARD_EVENT_HANDLER.TEST_KEY(hookKey)) {
                        hook(true); // active
                    }
                });
            });

            WIN.on(`keyup.__META_KEY_ZC`, () => {
                __HOOKS.each((hook, key) => {
                    let hookKey = key.split('.').shift();
                    if (KEYBOARD_EVENT_HANDLER.TEST_KEY(hookKey)) {
                        hook(false); // not active
                    }
                });
                __META_EVENT = null;
            });
            __META_KEY_INITIALIZED = true;
        }
    }

    /**
     *
     * @param key
     * @return {boolean}
     */
    static TEST_KEY(key) {
        // init only once
        KEYBOARD_EVENT_HANDLER.__INIT_EVENT();

        if (!__META_EVENT) {
            return false;
        }
        return !!__META_EVENT[key];
    }

    static ADD_HOOK(keyName, hook) {
        // init only once
        KEYBOARD_EVENT_HANDLER.__INIT_EVENT();
        __HOOK_ID++;

        let hook_id = `${keyName}.${__HOOK_ID}`;
        __HOOKS.set(hook_id, hook);
        return hook_id;
    }

    /**
     *
     * @param HOOK_ID
     */
    static REMOVE_HOOK(HOOK_ID) {
        __HOOKS.remove(HOOK_ID);
    }
}

export { KEYBOARD_EVENT_HANDLER };
